module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [15:0] quotient;

    always @(*) begin
        dividend = A;
        divisor = B;
        remainder = 0;
        quotient = 0;

        if (dividend[15:8] >= divisor) begin
            quotient[15:8] = 1;
            remainder = dividend[15:8] - divisor;
        end else begin
            quotient[15:8] = 0;
            remainder = dividend[15:8];
        end

        if (remainder[15:8] >= divisor) begin
            quotient[7:0] = 1;
            remainder = remainder[15:8] - divisor;
        end else begin
            quotient[7:0] = 0;
            remainder = remainder[15:8];
        end

        result = quotient;
        odd = remainder;
    end

endmodule
